function u(t){const e=t.match(/^\/(.+)\/([gimsuy]*)$/s);if(!e)return null;try{return new RegExp(e[1],e[2])}catch{return null}}function h(t){return t.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")}export function matchKeys(t,e,r){const c=u(e);if(c)return c.test(t);const s=r.caseSensitive?t:t.toLowerCase(),n=r.caseSensitive?e:e.toLowerCase();return r.matchWholeWords?n.split(/\s+/).length>1?s.includes(n):new RegExp(`(?:^|\\W)(${h(n)})(?:$|\\W)`).test(s):s.includes(n)}export function checkPrimaryKeys(t,e,r){const c={caseSensitive:e.caseSensitive??r.caseSensitive,matchWholeWords:e.matchWholeWords??r.matchWholeWords};return e.key.some(s=>s.trim()!==""&&matchKeys(t,s,c))}export function checkSecondaryLogic(t,e,r){const c=e.keysecondary;if(c.length===0)return!0;const s={caseSensitive:e.caseSensitive??r.caseSensitive,matchWholeWords:e.matchWholeWords??r.matchWholeWords},n=c.map(o=>matchKeys(t,o,s)),i=n.some(o=>o),a=n.every(o=>o);switch(e.selectiveLogic){case"AND_ANY":return i;case"AND_ALL":return a;case"NOT_ALL":return!a;case"NOT_ANY":return!i;default:return i}}export function checkEntryMatch(t,e,r){return checkPrimaryKeys(t,e,r)?e.selective?checkSecondaryLogic(t,e,r):!0:!1}
